// @vitest-environment node
/**
 * SPEC-023: coste con prompt caching — tarifas de caché en computeCostUsd
 * (retrocompatible con 2 argumentos), plegado de los componentes de caché en
 * inputTokens al registrar, y respeto del estimatedCostUsd ya calculado por
 * componentes (desviación declarada del implementador: camino recording:stop,
 * cuyo AiUsage llega con inputTokens ya plegado).
 * Generated by QA Dev agent.
 */
import { mkdtempSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import {
  CACHE_READ_USD_PER_MTOK,
  CACHE_WRITE_USD_PER_MTOK,
  computeCostUsd,
  recordInterviewUsage
} from '../../../src/main/aiCost'
import * as repository from '../../../src/main/db/repository'
import { initStore } from '../../../src/main/db/store'
import type { Interview } from '../../../src/renderer/src/types/domain'

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  }
}))

function seedInterview(): Interview {
  const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
  return repository.createInterview({ discoveryId: discovery.id, title: 'Captura medida' })
}

beforeEach(() => {
  initStore(mkdtempSync(join(tmpdir(), 'maurya-latency-cost-')))
})

describe('aiCost (prompt caching SPEC-023)', () => {
  // SPEC-023 · AC-07 (tarifas reales de caché: escritura 1,25× y lectura 0,1×)
  it('computes the cost with the four rates and stays byte-compatible with the historic 2-argument calls', () => {
    expect(CACHE_WRITE_USD_PER_MTOK).toBe(6.25)
    expect(CACHE_READ_USD_PER_MTOK).toBe(0.5)
    // Cada tarifa por separado
    expect(computeCostUsd(0, 0, 1_000_000, 0)).toBe(6.25)
    expect(computeCostUsd(0, 0, 0, 1_000_000)).toBe(0.5)
    // Combinado: 1000 in ($0.005) + 500 out ($0.0125) + 800 write ($0.005) + 4000 read ($0.002)
    expect(computeCostUsd(1000, 500, 800, 4000)).toBeCloseTo(0.0245, 10)
    // Retrocompatibilidad AC-08: 2 argumentos ≡ defaults a 0 ≡ valor histórico
    expect(computeCostUsd(1000, 500)).toBe(computeCostUsd(1000, 500, 0, 0))
    expect(computeCostUsd(1000, 500)).toBeCloseTo(0.0175, 10)
  })

  // SPEC-023 · AC-07 (registro: inputTokens = suma de los 3 componentes; coste ≠ tarificar caché a $5)
  it('folds the cache components into inputTokens and prices them with their own rates when recording', () => {
    const interview = seedInterview()

    recordInterviewUsage(interview.id, {
      inputTokens: 1000,
      outputTokens: 500,
      cacheCreationInputTokens: 800,
      cacheReadInputTokens: 4000
    })

    const usage = repository.getInterview(interview.id).aiUsage
    // El desglose reportado suma los tres componentes de entrada
    expect(usage).toMatchObject({ calls: 1, inputTokens: 5800, outputTokens: 500 })
    // El coste usa las 4 tarifas…
    expect(usage?.estimatedCostUsd).toBeCloseTo(computeCostUsd(1000, 500, 800, 4000), 10)
    // …y NO es el resultado de tarificar el total plegado a la tarifa de entrada
    expect(usage?.estimatedCostUsd).not.toBeCloseTo(computeCostUsd(5800, 500), 10)
  })

  // SPEC-023 · AC-08 (sin campos de caché el registro es idéntico al histórico)
  it('keeps the historic recording untouched when the response carries no cache fields', () => {
    const interview = seedInterview()

    recordInterviewUsage(interview.id, { inputTokens: 1000, outputTokens: 500 })

    expect(repository.getInterview(interview.id).aiUsage).toEqual({
      calls: 1,
      inputTokens: 1000,
      outputTokens: 500,
      estimatedCostUsd: computeCostUsd(1000, 500)
    })
  })

  // SPEC-023 · AC-07 (desviación declarada: estimatedCostUsd explícito se respeta —
  // recomputar desde el inputTokens ya plegado tarificaría el caché a $5/MTok)
  it('respects an explicit estimatedCostUsd computed by components instead of recomputing from folded tokens', () => {
    const interview = seedInterview()
    // Volcado de sesión del asistente: inputTokens YA plegado + coste por componentes
    const sessionCost = computeCostUsd(1000, 500, 800, 4000)

    recordInterviewUsage(interview.id, {
      calls: 3,
      inputTokens: 5800,
      outputTokens: 500,
      estimatedCostUsd: sessionCost
    })

    const usage = repository.getInterview(interview.id).aiUsage
    expect(usage).toMatchObject({ calls: 3, inputTokens: 5800, outputTokens: 500 })
    // Coste respetado tal cual (≠ computeCostUsd(5800, 500) = tarifa plana)
    expect(usage?.estimatedCostUsd).toBe(sessionCost)
    expect(usage?.estimatedCostUsd).not.toBeCloseTo(computeCostUsd(5800, 500), 10)
  })
})
